// ── Entrada ─────────────────────────────────────────
const webhook  = $('Webhook Evolution').first().json;
const comercios = $('Buscar Comercio').all().map(i => i.json);
const estados   = $('Buscar Estado Conversa').all().map(i => i.json);

const instance = webhook.instance;
const telefone = webhook.data.key.remoteJid;
const mensagem = (
  webhook.data.message?.conversation ||
  webhook.data.message?.extendedTextMessage?.text ||
  ''
).trim();

const comercio   = comercios[0] || {};
const comercioId = comercio.id || null;
const nomeComercio = comercio.nome_fantasia || 'nosso estabelecimento';

const estado = estados[0] || {};
const etapa  = estado.etapa || 'INICIO';

// ── Lógica de estado ────────────────────────────────
let novaEtapa  = etapa;
let resposta   = '';
let dadosExtra = {};
let criarPedido = false;

switch (etapa) {
  case 'INICIO':
    novaEtapa = 'AGUARDANDO_NOME';
    resposta  = `👋 Olá! Bem-vindo ao *${nomeComercio}*!\n\nPara fazermos sua entrega, preciso de algumas informações.\n\nQual é o seu *nome completo*?`;
    break;

  case 'AGUARDANDO_NOME':
    if (mensagem.length < 2) {
      resposta = 'Por favor, informe seu nome completo. 😊';
      break;
    }
    dadosExtra.nome = mensagem;
    novaEtapa = 'AGUARDANDO_ENDERECO';
    resposta  = `Olá, *${mensagem}*! 😊\n\nQual é o *endereço completo* de entrega?\n_(Ex: Rua das Flores, 123 - Centro)_`;
    break;

  case 'AGUARDANDO_ENDERECO':
    if (mensagem.length < 5) {
      resposta = 'Por favor, informe o endereço completo (rua, número, bairro). 📍';
      break;
    }
    dadosExtra.endereco = mensagem;
    novaEtapa = 'AGUARDANDO_PEDIDO';
    resposta  = `📍 Endereço confirmado: *${mensagem}*\n\nAgora me diga: o que você gostaria de *pedir*?\n_(Descreva os itens do pedido)_`;
    break;

  case 'AGUARDANDO_PEDIDO':
    if (mensagem.length < 2) {
      resposta = 'Por favor, descreva o que deseja pedir. 🛍️';
      break;
    }
    dadosExtra.pedido = mensagem;
    novaEtapa = 'AGUARDANDO_PAGAMENTO';
    resposta  = `🛍️ Pedido anotado: *${mensagem}*\n\nComo vai pagar?\n\n1️⃣  PIX\n2️⃣  Dinheiro\n3️⃣  Cartão`;
    break;

  case 'AGUARDANDO_PAGAMENTO': {
    const msg = mensagem.toLowerCase();
    let pagamento = 'A definir';
    if (msg.includes('1') || msg.includes('pix'))      pagamento = 'PIX';
    else if (msg.includes('2') || msg.includes('din')) pagamento = 'DINHEIRO';
    else if (msg.includes('3') || msg.includes('cart'))pagamento = 'CARTÃO';

    dadosExtra.pagamento = pagamento;
    novaEtapa   = 'FINALIZADO';
    criarPedido = true;
    resposta    = `✅ *Pedido confirmado!*\n\n👤 ${estado.nome}\n📦 ${estado.pedido}\n📍 ${estado.endereco}\n💳 ${pagamento}\n\nEm breve um motoboy vai buscar o seu pedido! 🏍️\n\nQualquer dúvida é só chamar aqui!`;
    break;
  }

  case 'FINALIZADO':
    // Cliente envia nova mensagem após pedido finalizado → recomeça
    novaEtapa = 'AGUARDANDO_PEDIDO';
    resposta  = `Olá de novo, *${estado.nome}*! 😊\n\nQuer fazer mais um pedido? Me diga o que deseja!`;
    break;

  default:
    novaEtapa = 'INICIO';
    resposta  = '👋 Olá! Para começar um novo pedido, qual é o seu *nome*?';
}

// ── Saída ─────────────────────────────────────────────
return [{
  json: {
    instance,
    telefone,
    resposta,
    criarPedido,
    upsertData: {
      telefone,
      instancia:     instance,
      comercio_id:   comercioId,
      etapa:         novaEtapa,
      nome:          dadosExtra.nome     || estado.nome     || null,
      endereco:      dadosExtra.endereco || estado.endereco || null,
      pedido:        dadosExtra.pedido   || estado.pedido   || null,
      pagamento:     dadosExtra.pagamento|| estado.pagamento|| null,
      atualizado_em: new Date().toISOString(),
    },
    pedidoData: criarPedido ? {
      comercio_id:      comercioId,
      cliente_nome:     dadosExtra.nome     || estado.nome,
      cliente_tel:      telefone.replace('@s.whatsapp.net', ''),
      endereco_destino: dadosExtra.endereco || estado.endereco,
      descricao:        dadosExtra.pedido   || estado.pedido,
      forma_pagamento:  dadosExtra.pagamento,
      valor_total:      0,
      status:           'PENDENTE',
      criado_em:        new Date().toISOString(),
    } : null,
  }
}];
